(function(){'use strict';document.addEventListener('DOMContentLoaded',function(){var form=document.getElementById('td-frontend-ticket-form');var formWrap=document.querySelector('.td-frontend-form-wrap');var successWrapper=document.getElementById('td-frontend-success-wrapper');var errorWrapper=document.getElementById('td-frontend-error-wrapper');if(!form||!formWrap){return}
form.addEventListener('submit',function(e){e.preventDefault();var title=form.querySelector('[name="td_title"]');var name=form.querySelector('[name="td_name"]');var email=form.querySelector('[name="td_email"]');var description=form.querySelector('[name="td_description"]');var errors=[];var existing=form.querySelectorAll('.td-field-error');for(var i=0;i<existing.length;i++){existing[i].remove()}
if(errorWrapper){errorWrapper.style.display='none';errorWrapper.innerHTML=''}
if(name&&name.value.trim()===''){errors.push({field:name,message:'Vul uw naam in.'})}
if(email&&email.value.trim()===''){errors.push({field:email,message:'Vul uw e-mailadres in.'})}else if(email&&!isValidEmail(email.value.trim())){errors.push({field:email,message:'Vul een geldig e-mailadres in.',})}
if(title&&title.value.trim()===''){errors.push({field:title,message:'Vul een onderwerp in.'})}
if(description&&description.value.trim()===''){errors.push({field:description,message:'Vul een beschrijving in.',})}
if(errors.length>0){for(var j=0;j<errors.length;j++){showFieldError(errors[j].field,errors[j].message)}
errors[0].field.focus();return}
if(!confirm('Weet u zeker dat u dit ticket wilt indienen? Er wordt zo snel mogelijk contact met u opgenomen.')){return}
var submitBtn=form.querySelector('.td-frontend-submit');if(submitBtn){submitBtn.disabled=!0;submitBtn.textContent='Bezig met verzenden...'}
var formData=new FormData(form);formData.append('action','td_submit_frontend_ticket');var xhr=new XMLHttpRequest();xhr.open('POST',typeof tdFrontend!=='undefined'?tdFrontend.ajaxUrl:'');xhr.setRequestHeader('X-Requested-With','XMLHttpRequest');xhr.onload=function(){if(submitBtn){submitBtn.disabled=!1;submitBtn.textContent='Ticket Indienen'}
var response;try{response=JSON.parse(xhr.responseText)}catch(err){showErrorMessage('Er is een fout opgetreden. Probeer het opnieuw.');return}
if(response.success&&response.data){formWrap.style.display='none';showSuccessMessage(response.data)}else{var msg=response.data&&response.data.message?response.data.message:'Er is een fout opgetreden. Probeer het opnieuw.';showErrorMessage(msg)}};xhr.onerror=function(){if(submitBtn){submitBtn.disabled=!1;submitBtn.textContent='Ticket Indienen'}
showErrorMessage('Er is een verbindingsfout opgetreden. Controleer uw internetverbinding en probeer het opnieuw.')};xhr.send(formData)});function showSuccessMessage(data){if(!successWrapper){return}
var html='<div class="td-frontend-notice td-frontend-success td-frontend-success-extended">';html+='<p class="td-success-title">'+escapeHtml(data.message||'Uw ticket is succesvol ingediend.')+'</p>';if(data.submitted){html+='<div class="td-submitted-summary">';html+='<p class="td-summary-heading">Dit is wat u heeft ingediend:</p>';html+='<dl class="td-summary-list">';html+='<dt>Naam:</dt><dd>'+escapeHtml(data.submitted.naam||'-')+'</dd>';html+='<dt>E-mail:</dt><dd>'+escapeHtml(data.submitted.email||'-')+'</dd>';html+='<dt>Onderwerp:</dt><dd>'+escapeHtml(data.submitted.onderwerp||'-')+'</dd>';html+='<dt>Prioriteit:</dt><dd>'+escapeHtml(data.submitted.prioriteit||'-')+'</dd>';var desc=(data.submitted.beschrijving||'-');html+='<dt>Beschrijving:</dt><dd>'+escapeHtml(desc).replace(/\n/g,'<br>')+'</dd>';html+='</dl>';html+='</div>'}
html+='<p class="td-success-footer">Wij nemen zo snel mogelijk contact met u op.</p>';html+='<button type="button" class="td-frontend-submit-another td-submit-another-btn">Nog een ticket indienen</button>';html+='</div>';successWrapper.innerHTML=html;successWrapper.style.display='block';successWrapper.scrollIntoView({behavior:'smooth',block:'start'});var anotherBtn=successWrapper.querySelector('.td-submit-another-btn');if(anotherBtn){anotherBtn.addEventListener('click',function(){successWrapper.style.display='none';successWrapper.innerHTML='';formWrap.style.display='';form.reset()})}}
function showErrorMessage(message){if(!errorWrapper){return}
errorWrapper.innerHTML='<div class="td-frontend-notice td-frontend-error"><p>'+escapeHtml(message)+'</p></div>';errorWrapper.style.display='block';errorWrapper.scrollIntoView({behavior:'smooth',block:'start'})}
function showFieldError(field,message){var errorEl=document.createElement('span');errorEl.className='td-field-error';errorEl.textContent=message;errorEl.style.color='#d63638';errorEl.style.fontSize='12px';errorEl.style.display='block';errorEl.style.marginTop='4px';field.parentNode.appendChild(errorEl);field.style.borderColor='#d63638'}
function escapeHtml(text){if(!text){return''}
var div=document.createElement('div');div.textContent=text;return div.innerHTML}
function isValidEmail(email){return/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)}})})()